213 PreservedAnalyses CoroCleanupPass::run(Module &M,
214                                        ModuleAnalysisManager &MAM) {
215   if (!declaresCoroCleanupIntrinsics(M))
216     return PreservedAnalyses::all();
217 
218   FunctionAnalysisManager &FAM =
219       MAM.getResult<FunctionAnalysisManagerModuleProxy>(M).getManager();
220 
221   FunctionPassManager FPM;
222   FPM.addPass(SimplifyCFGPass());
223 
224   PreservedAnalyses FuncPA;
225   FuncPA.preserveSet<CFGAnalyses>();
226 
227   Lowerer L(M);
228   for (auto &F : M) {
229     if (L.lower(F)) {
230       FAM.invalidate(F, FuncPA);
231       FPM.run(F, FAM);
232     }
233   }
234 
235   return PreservedAnalyses::none();
236 }
